import React, { useState } from 'react';

const App = () => {
  const [selectedMethod, setSelectedMethod] = useState(null);
  const [smsCode, setSmsCode] = useState('');
  const [emailCode, setEmailCode] = useState('');
  const [error, setError] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log(selectedMethod, smsCode, emailCode);
  }

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <form onSubmit={handleSubmit} className="bg-white p-4 rounded shadow-md">
        <h2 className="text-center mb-4">Enroll in 2FA</h2>
        <div className="flex justify-center mb-4">
          <button className="bg-[#C06C88] px-4 py-2 rounded text-white" type="button" onClick={() => setSelectedMethod('SMS')}>SMS</button>
          <button className="bg-[#C06C88] px-4 py-2 rounded text-white" type="button" onClick={() => setSelectedMethod('Email')}>Email</button>
        </div>
        {selectedMethod === 'SMS' && (
          <div className="mb-4">
            <label className="block mb-2">SMS Code:</label>
            <input
              type="text"
              className="block w-full p-2 text-gray-700" 
              value={smsCode}
              onChange={(e) => setSmsCode(e.target.value)}
              placeholder="123456"
            />
          </div>
        )}
        {selectedMethod === 'Email' && (
          <div className="mb-4">
            <label className="block mb-2">Email Code:</label>
            <input
              type="text"
              className="block w-full p-2 text-gray-700" 
              value={emailCode}
              onChange={(e) => setEmailCode(e.target.value)}
              placeholder="123456"
            />
          </div>
        )}
        {error && (
          <div className="bg-red-500 text-white p-2 rounded mb-4">{error}</div>
        )}
        <button className="bg-[#411C56] px-4 py-2 rounded text-white" type="submit">Submit</button>
      </form>
    </div>
  );
};

export default App;
